-- ============================================
-- Legislacao full-site: fabio-trad / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/160587
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = fabio-trad-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 85
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=160587, tipo Deputado(a), ordemAssinatura=1.
-- 15 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'fabio-trad';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'fabio-trad: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-trad: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2342978', '2342934', '2337179', '2336496', '2336494', '2336493', '2336492', '2334446', '2333604', '2333152', '2332916', '2328768', '2328757', '2328740', '2327792', '2327417', '2326302', '2325315', '2321441', '2321261', '2320665', '2318707', '2318701', '2328772', '2328761', '2328753', '2328739', '2327791', '2325539', '2324941', '2324021', '2321294', '2321259', '2320059', '2318706', '2330170', '2328771', '2328760', '2328752', '2328418', '2327790', '2324940', '2324020', '2321269', '2320678', '2318705', '2328770', '2328759', '2328748', '2327794', '2327789', '2325459', '2324461', '2321267', '2320673', '2318704', '2330691', '2329723', '2328769', '2328758', '2328741', '2327793', '2327418', '2326633', '2324442', '2322457', '2321263', '2320666', '2318712', '2318703', '2332327', '2331412', '2332326', '2326811', '2332325', '2330874', '2325375', '2332328', '2330470', '2331476', '2331290', '2330166', '2329722', '2326646', '2325534');
  IF target_present <> 85 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-trad: esperadas 85 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2342978', '2342934', '2337179', '2336496', '2336494', '2336493', '2336492', '2334446', '2333604', '2333152', '2332916', '2328768', '2328757', '2328740', '2327792', '2327417', '2326302', '2325315', '2321441', '2321261', '2320665', '2318707', '2318701', '2328772', '2328761', '2328753', '2328739', '2327791', '2325539', '2324941', '2324021', '2321294', '2321259', '2320059', '2318706', '2330170', '2328771', '2328760', '2328752', '2328418', '2327790', '2324940', '2324020', '2321269', '2320678', '2318705', '2328770', '2328759', '2328748', '2327794', '2327789', '2325459', '2324461', '2321267', '2320673', '2318704', '2330691', '2329723', '2328769', '2328758', '2328741', '2327793', '2327418', '2326633', '2324442', '2322457', '2321263', '2320666', '2318712', '2318703', '2332327', '2331412', '2332326', '2326811', '2332325', '2330874', '2325375', '2332328', '2330470', '2331476', '2331290', '2330166', '2329722', '2326646', '2325534')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'fabio-trad-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-trad: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao fabio-trad: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

